import { dirname, join, extname, resolve } from "path"
import { statSync, readdirSync, readFileSync, writeFileSync } from "fs"
import { fileURLToPath } from "url"

// prettier.js 3.5.3
const B64_PRETTIER_STANDALONE =
  ""
const prettierCode = Buffer.from(B64_PRETTIER_STANDALONE, "base64").toString("utf8")
new Function(prettierCode)()
const prettier = globalThis.prettier

// babel.js
const B64_BABEL_STANDALONE =
  ""
const babelPluginCode = Buffer.from(B64_BABEL_STANDALONE, "base64").toString("utf8")
new Function(babelPluginCode)()

// estree.js
const B64_ESTREE_STANDALONE =
  ""
const estreePluginCode = Buffer.from(B64_ESTREE_STANDALONE, "base64").toString(
  "utf8"
)
new Function(estreePluginCode)()

// html.js
const B64_HTML_STANDALONE =
  ""
const htmlPluginCode = Buffer.from(B64_HTML_STANDALONE, "base64").toString("utf8")
new Function(htmlPluginCode)()

// yaml.js
const B64_YAML_STANDALONE =
  ""
const yamlPluginCode = Buffer.from(B64_YAML_STANDALONE, "base64").toString("utf8")
new Function(yamlPluginCode)()

// markdown.js
const B64_MARKDOWN_STANDALONE =
  ""
const markdownPluginCode = Buffer.from(B64_MARKDOWN_STANDALONE, "base64").toString(
  "utf8"
)
new Function(markdownPluginCode)()

// prettier-plugin-void-html.js
const B64_VOIDHTML_STANDALONE =
  ""
const voidHtmlPluginCode = Buffer.from(B64_VOIDHTML_STANDALONE, "base64").toString(
  "utf8"
)
new Function(voidHtmlPluginCode)()

// ---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------
// PRETTIER IMPLEMENTATION
// ---------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------------

const __filename = fileURLToPath(import.meta.url)
const __dirname = dirname(__filename)
const startDir = resolve(__dirname, ".")

function findFilesRecursiveSync(dir, ext) {
  const files = []

  try {
    const stats = statSync(dir)
    if (!stats.isDirectory()) {
      return files
    }
  } catch (e) {
    return files
  }

  const entries = readdirSync(dir)

  for (const entry of entries) {
    const fullPath = join(dir, entry)

    try {
      const stats = statSync(fullPath)

      if (stats.isDirectory()) {
        files.push(...findFilesRecursiveSync(fullPath, ext))
      } else if (stats.isFile() && extname(entry) === ext) {
        files.push(fullPath)
      }
    } catch (e) {}
  }

  return files
}

const formatFiles = async (fileList) => {
  for (const filePath of fileList) {
    const fileData = readFileSync(filePath, "utf8")
    const newFileData = await parseCode(fileData, filePath)
    writeFileSync(filePath, newFileData)
  }
}

const parseCode = async (codeToFormat, filePath) => {
  const selectedParser =
    filePath.endsWith(".html") || filePath.endsWith(".htm")
      ? "html"
      : filePath.endsWith(".md")
        ? "markdown"
        : "babel"

  try {
    const formattedCode = await prettier.format(codeToFormat, {
      parser: selectedParser,
      arrowParens: "always",
      printWidth: 85,
      semi: false,
      tabWidth: 2,
      trailingComma: "es5",
      plugins: [
        prettierPlugins.babel,
        prettierPlugins.estree,
        prettierPlugins.html,
        prettierPlugins.yaml,
        prettierPlugins.markdown,
        prettierPlugins.voidHtml,
      ],
    })
    return formattedCode
  } catch (error) {
    return codeToFormat
  }
}

const runPrettier = async () => {
  formatFiles(findFilesRecursiveSync(startDir, ".html"))
  formatFiles(findFilesRecursiveSync(startDir, ".js"))
}

runPrettier()
